class Solution:
    def rotate(self, matrix: list[list[int]]) -> None:
        n = len(matrix)
        new = [[0] * n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                new[j][n - 1 - i] = matrix[i][j]
        # Copy back
        for i in range(n):
            matrix[i] = new[i]

class Solution:
    def rotate(self, matrix: list[list[int]]) -> None:
        n = len(matrix)
        # Transpose: swap matrix[i][j] with matrix[j][i]
        for i in range(n):
            for j in range(i + 1, n):
                matrix[i][j], matrix[j][i] = matrix[j][i], matrix[i][j]
        # Reverse each row
        for i in range(n):
            matrix[i].reverse()   # or matrix[i] = matrix[i][::-1]

class Solution:
    def spiralOrder(self, matrix: list[list[int]]) -> list[int]:
        result = []
        if not matrix:
            return result
        top, bottom = 0, len(matrix) - 1
        left, right = 0, len(matrix[0]) - 1

        while top <= bottom and left <= right:
            # Top row: left to right
            for col in range(left, right + 1):
                result.append(matrix[top][col])
            top += 1

            # Right column: top to bottom
            for row in range(top, bottom + 1):
                result.append(matrix[row][right])
            right -= 1

            # Bottom row: right to left (if still valid)
            if top <= bottom:
                for col in range(right, left - 1, -1):
                    result.append(matrix[bottom][col])
                bottom -= 1

            # Left column: bottom to top (if still valid)
            if left <= right:
                for row in range(bottom, top - 1, -1):
                    result.append(matrix[row][left])
                left += 1

        return result

class Solution:
    def setZeroes(self, matrix: list[list[int]]) -> None:
        m, n = len(matrix), len(matrix[0])
        rows, cols = set(), set()

        for i in range(m):
            for j in range(n):
                if matrix[i][j] == 0:
                    rows.add(i)
                    cols.add(j)

        for i in range(m):
            for j in range(n):
                if i in rows or j in cols:
                    matrix[i][j] = 0

class Solution:
    def setZeroes(self, matrix: list[list[int]]) -> None:
        m, n = len(matrix), len(matrix[0])
        first_col_zero = False

        # Use first row and column as markers
        for i in range(m):
            if matrix[i][0] == 0:
                first_col_zero = True
            for j in range(1, n):
                if matrix[i][j] == 0:
                    matrix[i][0] = 0
                    matrix[0][j] = 0

        # Zero out cells based on markers (skip first row/col for now)
        for i in range(1, m):
            for j in range(1, n):
                if matrix[i][0] == 0 or matrix[0][j] == 0:
                    matrix[i][j] = 0

        # Handle first row
        if matrix[0][0] == 0:
            for j in range(n):
                matrix[0][j] = 0

        # Handle first column
        if first_col_zero:
            for i in range(m):
                matrix[i][0] = 0

class Solution:
    def isHappy(self, n: int) -> bool:
        seen = set()
        while n != 1 and n not in seen:
            seen.add(n)
            n = sum(int(digit) ** 2 for digit in str(n))
        return n == 1

class Solution:
    def isHappy(self, n: int) -> bool:
        def next_num(x):
            total = 0
            while x > 0:
                x, digit = divmod(x, 10)   # divmod splits into (quotient, remainder)
                total += digit ** 2
            return total

        slow = n
        fast = next_num(n)
        while fast != 1 and slow != fast:
            slow = next_num(slow)
            fast = next_num(next_num(fast))
        return fast == 1

class Solution:
    def plusOne(self, digits: list[int]) -> list[int]:
        for i in range(len(digits) - 1, -1, -1):
            if digits[i] < 9:
                digits[i] += 1
                return digits
            digits[i] = 0   # carry over
        # All were 9s: need an extra leading 1
        return [1] + digits

class Solution:
    def myPow(self, x: float, n: int) -> float:
        if n < 0:
            x = 1 / x
            n = -n
        result = 1
        for _ in range(n):
            result *= x
        return result

class Solution:
    def myPow(self, x: float, n: int) -> float:
        if n == 0:
            return 1
        if n < 0:
            x = 1 / x
            n = -n

        # Recursive helper
        def helper(base, exp):
            if exp == 0:
                return 1
            half = helper(base, exp // 2)
            if exp % 2 == 0:
                return half * half
            else:
                return half * half * base

        return helper(x, n)

class Solution:
    def myPow(self, x: float, n: int) -> float:
        if n < 0:
            x = 1 / x
            n = -n

        result = 1
        current_product = x

        while n > 0:
            if n % 2 == 1:   # if current bit is 1
                result *= current_product
            current_product *= current_product   # square the base
            n //= 2   # shift to next bit

        return result

from collections import defaultdict

class DetectSquares:
    def __init__(self):
        self.points = defaultdict(int)   # (x, y) -> count
        self.x_coords = defaultdict(list)  # x -> list of y values

    def add(self, point: list[int]) -> None:
        x, y = point
        self.points[(x, y)] += 1
        if y not in self.x_coords[x]:
            self.x_coords[x].append(y)

    def count(self, point: list[int]) -> int:
        x1, y1 = point
        total = 0

        # Look for diagonal corners: points with same y1 but different x
        for x2 in self.x_coords:
            if x2 == x1:
                continue
            side_len = abs(x2 - x1)
            # Two possible y values for the square
            for y2 in [y1 + side_len, y1 - side_len]:
                # Check if all four corners exist
                total += (self.points[(x2, y1)] * 
                          self.points[(x1, y2)] * 
                          self.points[(x2, y2)])

        return total
